import React, { useState } from 'react';
import axios from '../api'; // Proxy

const BudgetForm = ({ userId, onAdd }) => {
  const [month, setMonth] = useState('');
  const [limit, setLimit] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post('/budgets', { month, limit: parseFloat(limit) });
      onAdd();
      setMonth('');
      setLimit('');
    } catch (err) {
      alert(err.response.data.error);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white p-6 rounded-lg shadow mb-6">
      <h3 className="text-xl font-bold mb-4">Set Budget</h3>
      <div className="grid grid-cols-2 gap-4 mb-4">
        <input type="month" value={month} onChange={(e) => setMonth(e.target.value)} className="p-3 border rounded-lg" required />
        <input type="number" value={limit} onChange={(e) => setLimit(e.target.value)} placeholder="Limit $" className="p-3 border rounded-lg" required />
      </div>
      <button type="submit" className="w-full bg-green-500 text-white p-3 rounded-lg font-semibold">Set Budget</button>
    </form>
  );
};

export default BudgetForm;
